import { execSync } from "child_process";
import fs from "fs";
function putText(n,s){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const b={message:'x',branch:'main',content:Buffer.from(s,'utf8').toString('base64')};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pf.json',JSON.stringify(b));execSync('curl -s --max-time 40 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pf.json "'+url+'"',{encoding:'utf8'});}
function putBin(n,localPath){const repo=process.env.GH_REPO,tok=process.env.GH_TOKEN;const url='https://api.github.com/repos/'+repo+'/contents/analize/'+n;let sha='';try{sha=JSON.parse(execSync('curl -s --max-time 30 -H "Authorization: Bearer '+tok+'" "'+url+'?ref=main&t='+Date.now()+'"',{encoding:'utf8'})).sha||'';}catch(e){}const content=fs.readFileSync(localPath).toString('base64');const b={message:'x',branch:'main',content:content};if(sha)b.sha=sha;fs.writeFileSync('/tmp/pb.json',JSON.stringify(b));execSync('curl -s --max-time 60 -X PUT -H "Authorization: Bearer '+tok+'" -d @/tmp/pb.json "'+url+'"',{encoding:'utf8'});}
const BASE='https://dev.avesa.lt';const U=process.env.WP_USER||'';const P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const F={"main": "", "petui": "", "css": "", "js": ""};
function api(method,path,body){const auth='-u "'+U+':'+P+'"';let cmd;if(body){fs.writeFileSync('/tmp/b.json',JSON.stringify(body));cmd='curl -s -k -A "Mozilla/5.0" --max-time 90 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' -H "Content-Type: application/json" --data-binary @/tmp/b.json "'+BASE+path+'"';}else{cmd='curl -s -k -A "Mozilla/5.0" --max-time 60 -w "\nHTTP:%{http_code}" '+auth+' -X '+method+' "'+BASE+path+'"';}let r;try{r=execSync(cmd,{encoding:'utf8',maxBuffer:30000000});}catch(e){r=(e.stdout||'')+'\nHTTP:TIMEOUT';}return{code:(r.match(/HTTP:(\S+)$/)||[])[1]||'?',body:r.replace(/\nHTTP:\S+$/,'')};}
function sh(c){try{return execSync(c,{encoding:'utf8',maxBuffer:30000000});}catch(e){return (e.stdout||'')+'[ERR]';}}
(async()=>{
  let out=''; const L=s=>{out+=s+'\n'; console.log(s);};

  // Deploy: sukuria assets dir + rasom failus
  const depPHP = "if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_ui_dep']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;$d=WP_PLUGIN_DIR.'/petshop-core';@mkdir($d.'/assets',0755,true);$o=array();$o['ui']=@file_put_contents($d.'/includes/class-pet-ui.php',base64_decode('"+F.petui+"'));$o['css']=@file_put_contents($d.'/assets/pet-form.css',base64_decode('"+F.css+"'));$o['js']=@file_put_contents($d.'/assets/pet-form.js',base64_decode('"+F.js+"'));$o['main']=@file_put_contents($d.'/petshop-core.php',base64_decode('"+F.main+"'));header('Content-Type:application/json');echo wp_json_encode($o);exit;},6);";
  const c=api('POST','/wp-json/code-snippets/v1/snippets',{name:'UI Dep tmp',desc:'x',code:depPHP,scope:'global',active:true,priority:5});
  let sid=0;try{sid=JSON.parse(c.body).id;}catch(e){}
  execSync('sleep 2');
  L('deploy: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_ui_dep=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid) api('POST','/wp-json/code-snippets/v1/snippets/'+sid+'/deactivate',{});

  // Reactivate (flush rewrite)
  const actPHP = "if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_ui_act']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;if(!function_exists('activate_plugin'))require_once ABSPATH.'wp-admin/includes/plugin.php';deactivate_plugins('petshop-core/petshop-core.php');$e=activate_plugin('petshop-core/petshop-core.php');header('Content-Type:application/json');echo wp_json_encode(array('active'=>is_plugin_active('petshop-core/petshop-core.php'),'err'=>is_wp_error($e)?$e->get_error_message():null,'ver'=>defined('PETSHOP_CORE_VERSION')?PETSHOP_CORE_VERSION:'?'));exit;},6);";
  const c2=api('POST','/wp-json/code-snippets/v1/snippets',{name:'UI Act tmp',desc:'x',code:actPHP,scope:'global',active:true,priority:5});
  let sid2=0;try{sid2=JSON.parse(c2.body).id;}catch(e){}
  execSync('sleep 2');
  L('reactivate: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_ui_act=1&token=cmplz_6680aa2a42151d54fa8d64ec"'));
  if(sid2) api('POST','/wp-json/code-snippets/v1/snippets/'+sid2+'/deactivate',{});

  // Sukuriu test puslapi su shortcode
  const pagePHP = "if(!defined('ABSPATH'))return;\nadd_action('wp_loaded',function(){if(($_GET['ps_mkpage']??'')!=='1')return;if(($_GET['token']??'')!=='cmplz_6680aa2a42151d54fa8d64ec')return;$ex=get_page_by_path('anketa-testas');if($ex){echo wp_json_encode(array('exists'=>$ex->ID,'url'=>get_permalink($ex->ID)));exit;}$id=wp_insert_post(array('post_title'=>'Anketa testas','post_name'=>'anketa-testas','post_content'=>'[petshop_pet_form]','post_status'=>'publish','post_type'=>'page'));header('Content-Type:application/json');echo wp_json_encode(array('id'=>$id,'url'=>get_permalink($id)));exit;},6);";
  const c3=api('POST','/wp-json/code-snippets/v1/snippets',{name:'UI Page tmp',desc:'x',code:pagePHP,scope:'global',active:true,priority:5});
  let sid3=0;try{sid3=JSON.parse(c3.body).id;}catch(e){}
  execSync('sleep 2');
  const pageR=sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/?ps_mkpage=1&token=cmplz_6680aa2a42151d54fa8d64ec"');
  L('page: '+pageR);
  if(sid3) api('POST','/wp-json/code-snippets/v1/snippets/'+sid3+'/deactivate',{});

  // Assets pasiekiami?
  L('css HTTP: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 20 -o /dev/null -w "%{http_code}" "'+BASE+'/wp-content/plugins/petshop-core/assets/pet-form.css"'));
  L('js HTTP: '+sh('curl -s -k -A "Mozilla/5.0" --max-time 20 -o /dev/null -w "%{http_code}" "'+BASE+'/wp-content/plugins/petshop-core/assets/pet-form.js"'));

  // Anketos puslapio HTML — ar yra #pspet-form ir ar assets uzkrauti
  const html=sh('curl -s -k -A "Mozilla/5.0" --max-time 30 "'+BASE+'/anketa-testas/?nc='+Date.now()+'"');
  L('has_form_div: '+(html.indexOf('id="pspet-form"')>=0));
  L('has_css: '+(html.indexOf('pet-form.css')>=0));
  L('has_js: '+(html.indexOf('pet-form.js')>=0));
  L('has_config: '+(html.indexOf('PSPetConfig')>=0));

  putText('ui_deploy.txt', out);
})();
